    def _sign(self, data: bytes, algorithm: str) -> bytes:
        """Sign data with the specified algorithm."""
        if algorithm == "HS256":
            if not self._hs256_secret:
                raise JWTError("HS256 secret not configured")
            return hmac.new(self._hs256_secret, data, hashlib.sha256).digest()
        elif algorithm == "RS256":
            if not self._rs256_private_key:
                raise JWTError("RS256 private key not configured")
            return self._rs256_private_key.sign(
                data,
                padding.PKCS1v15(),
                hashes.SHA256(),
            )
        else:
            raise JWTInvalidAlgorithmError(f"Unsupported algorithm: {algorithm}")

    def _verify_signature(self, data: bytes, signature: bytes, algorithm: str):
        """Verify signature with the specified algorithm."""
        if algorithm == "HS256":
            if not self._hs256_secret:
                raise JWTError("HS256 secret not configured for verification")
            expected_signature = hmac.new(
                self._hs256_secret, data, hashlib.sha256
            ).digest()
            if not hmac.compare_digest(signature, expected_signature):
                raise JWTInvalidSignatureError("Invalid HS256 signature")
        elif algorithm == "RS256":
            if not self._rs256_public_key:
                raise JWTError("RS256 public key not configured for verification")
            try:
                self._rs256_public_key.verify(
                    signature,
                    data,
                    padding.PKCS1v15(),
                    hashes.SHA256(),
                )
            except InvalidSignature:
                raise JWTInvalidSignatureError("Invalid RS256 signature")
        else:
            raise JWTInvalidAlgorithmError(f"Unsupported algorithm: {algorithm}")

    def jwt_required(self, expected_algorithm: Optional[str] = None):
        """
        Flask route decorator that requires a valid JWT token.

        The token is extracted from the Authorization header (Bearer scheme).
        The decoded payload is stored in flask.g.jwt_payload.
        """

        def decorator(f):
            @wraps(f)
            def decorated_function(*args, **kwargs):
                auth_header = request.headers.get("Authorization", "")

                if not auth_header.startswith("Bearer "):
                    return jsonify({"error": "Missing or invalid Authorization header"}), 401

                token = auth_header[7:].strip()

                if not token:
                    return jsonify({"error": "Empty token"}), 401

                try:
                    payload = self.verify_token(
                        token, expected_algorithm=expected_algorithm
                    )
                    g.jwt_payload = payload
                except JWTExpiredError as e:
                    logger.info("Expired token: %s", e)
                    return jsonify({"error": "Token expired"}), 401
                except JWTInvalidSignatureError as e:
                    logger.warning("Invalid signature: %s", e)
                    return jsonify({"error": "Invalid token signature"}), 401
                except JWTInvalidAlgorithmError as e:
                    logger.warning("Algorithm error: %s", e)
                    return jsonify({"error": "Invalid token algorithm"}), 401
                except JWTError as e:
                    logger.warning("JWT error: %s", e)
                    return jsonify({"error": "Invalid token"}), 401

                return f(*args, **kwargs)

            return decorated_function

        return decorator


