    app.config["JWT_ISSUER"] = os.environ.get("JWT_ISSUER", "my-auth-service")
    app.config["JWT_AUDIENCE"] = os.environ.get("JWT_AUDIENCE", "my-api")
    app.config["JWT_CLOCK_SKEW"] = int(os.environ.get("JWT_CLOCK_SKEW", "30"))
    app.config["JWT_DEFAULT_EXPIRY"] = int(os.environ.get("JWT_DEFAULT_EXPIRY", "3600"))

    jwt_manager = JWTManager(app)

    # Generate RS256 keys for demonstration (in production, load from secure storage)
    jwt_manager.generate_rs256_keys(2048)

    @app.route("/health", methods=["GET"])
    def health():
        return jsonify({"status": "healthy"}), 200

    @app.route("/auth/token/hs256", methods=["POST"])
    def create_hs256_token():
        """Create an HS256 token (for internal services)."""
        data = request.get_json(silent=True) or {}
        subject = data.get("sub", "internal-service")
        custom_claims = data.get("claims", {})

        if not isinstance(custom_claims, dict):
            return jsonify({"error": "claims must be a dictionary"}), 400

        payload = {"sub": str(subject), **custom_claims}

        try:
            token = jwt_manager.create_token(payload, algorithm="HS256")
            return jsonify({"token": token, "algorithm": "HS256"}), 200
        except JWTError as e:
            return jsonify({"error": str(e)}), 500

    @app.route("/auth/token/rs256", methods=["POST"])
    def create_rs256_token():
        """Create an RS256 token (for public APIs)."""
        data = request.get_json(silent=True) or {}
        subject = data.get("sub", "api-user")
        custom_claims = data.get("claims", {})

        if not isinstance(custom_claims, dict):
            return jsonify({"error": "claims must be a dictionary"}), 400

        payload = {"sub": str(subject), **custom_claims}

        try:
            token = jwt_manager.create_token(payload, algorithm="RS256")
            return jsonify({"token": token, "algorithm": "RS256"}), 200
        except JWTError as e:
            return jsonify({"error": str(e)}), 500

